import { h, text } from '../core/index.js';
import { createSignal, createEffect, batch } from '../state/index.js';
import { injectBase, cx } from './_base.js';
import { caret } from './_behaviors.js';

// ═══════════════════════════════════════════════════════════════
// HELPERS
// ═══════════════════════════════════════════════════════════════

const resolve = (v) => typeof v === 'function' ? v() : v;
const ROW_H = 40; // virtual scroll row height (px)
const VIRT_THRESHOLD = 500;
const MIN_COL_W = 50;

/** Default comparator — handles string, number, date, null */
function defaultCmp(a, b) {
  if (a == null && b == null) return 0;
  if (a == null) return -1;
  if (b == null) return 1;
  if (typeof a === 'number' && typeof b === 'number') return a - b;
  return String(a).localeCompare(String(b));
}

/** CSV-escape a cell value */
function csvCell(v) {
  if (v == null) return '';
  const s = String(v);
  return /[",\n\r]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}

// ═══════════════════════════════════════════════════════════════
// DATATABLE COMPONENT
// ═══════════════════════════════════════════════════════════════

/**
 * DataTable — Enterprise data grid with sorting, pagination, selection,
 * column pinning, cell editing, row expansion, filtering, export, virtual
 * scrolling, and column resizing.
 *
 * @param {Object} props
 * @param {Array<{key:string,label:string,width?:string,sortable?:boolean,filterable?:boolean,pinned?:'left'|'right',render?:Function,editable?:boolean,align?:'left'|'center'|'right',sort?:Function}>} props.columns
 * @param {Array<Object>|Function} props.data
 * @param {Object} [props.pagination]
 * @param {'single'|'multi'|'none'} [props.selection='none']
 * @param {Function} [props.onSelectionChange]
 * @param {boolean} [props.striped=false]
 * @param {boolean} [props.hoverable=true]
 * @param {boolean} [props.stickyHeader=false]
 * @param {Function} [props.onSort]
 * @param {Function} [props.rowKey]
 * @param {Function} [props.onCellEdit]
 * @param {boolean} [props.expandable=false]
 * @param {Function} [props.expandRender]
 * @param {boolean} [props.exportable=false]
 * @param {string} [props.emptyText='No data']
 * @param {string} [props.class]
 * @returns {HTMLElement}
 */
export function DataTable(props = {}) {
  injectBase();

  const {
    columns: rawCols = [],
    data: rawData,
    pagination: pgCfg,
    selection = 'none',
    onSelectionChange,
    striped = false,
    hoverable = true,
    stickyHeader = false,
    onSort,
    rowKey = (r, i) => i,
    onCellEdit,
    expandable = false,
    expandRender,
    exportable = false,
    emptyText = 'No data',
    class: cls
  } = props;

  // ─────────────────────────────────────────────────────────────
  // STATE
  // ─────────────────────────────────────────────────────────────

  // Sort: array of { key, direction:'asc'|'desc' }
  const [sortCols, setSortCols] = createSignal([]);
  // Pagination
  const [page, setPage] = createSignal(1);
  const [pageSize, setPageSize] = createSignal(pgCfg ? pgCfg.pageSize || 10 : 10);
  // Selection: Set of rowKey values
  const [selected, setSelected] = createSignal(new Set());
  // Last clicked index (for shift+click range)
  let lastClickIdx = -1;
  // Expanded: Set of rowKey values
  const [expanded, setExpanded] = createSignal(new Set());
  // Column filters: { [key]: string }
  const [filters, setFilters] = createSignal({});
  // Column widths overrides (from resize): { [key]: number (px) }
  const [colWidths, setColWidths] = createSignal({});
  // Virtual scroll offset
  const [scrollTop, setScrollTop] = createSignal(0);

  // ─────────────────────────────────────────────────────────────
  // DERIVED DATA PIPELINE
  // ─────────────────────────────────────────────────────────────

  /** Resolve raw data (may be signal getter) */
  const getData = () => resolve(rawData) || [];

  /** Apply client-side filters */
  const getFiltered = () => {
    const d = getData();
    const f = filters();
    const keys = Object.keys(f).filter(k => f[k]);
    if (!keys.length) return d;
    return d.filter(row =>
      keys.every(k => {
        const v = row[k];
        return v != null && String(v).toLowerCase().includes(f[k].toLowerCase());
      })
    );
  };

  /** Apply client-side sort */
  const getSorted = () => {
    const d = getFiltered();
    const sc = sortCols();
    if (!sc.length) return d;
    const sorted = [...d];
    sorted.sort((a, b) => {
      for (const { key, direction } of sc) {
        const col = rawCols.find(c => c.key === key);
        const cmp = col && col.sort ? col.sort : defaultCmp;
        const r = cmp(a[key], b[key]);
        if (r !== 0) return direction === 'asc' ? r : -r;
      }
      return 0;
    });
    return sorted;
  };

  /** Total row count (for pagination) */
  const getTotal = () => {
    if (pgCfg && pgCfg.serverSide && pgCfg.total != null) return resolve(pgCfg.total);
    return getSorted().length;
  };

  /** Page count */
  const getPageCount = () => Math.max(1, Math.ceil(getTotal() / pageSize()));

  /** Paginated rows — client-side slicing unless serverSide or no pagination */
  const getPageData = () => {
    const sorted = getSorted();
    if (!pgCfg || pgCfg.serverSide) return sorted;
    const ps = pageSize();
    const p = page();
    return sorted.slice((p - 1) * ps, p * ps);
  };

  // ─────────────────────────────────────────────────────────────
  // SORT LOGIC
  // ─────────────────────────────────────────────────────────────

  function handleSort(key, multi) {
    setSortCols(prev => {
      const idx = prev.findIndex(s => s.key === key);
      let next;
      if (idx === -1) {
        // Add new sort column
        const entry = { key, direction: 'asc' };
        next = multi ? [...prev, entry] : [entry];
      } else {
        const cur = prev[idx];
        if (cur.direction === 'asc') {
          // Toggle to desc
          next = [...prev];
          next[idx] = { key, direction: 'desc' };
        } else {
          // Remove sort
          next = prev.filter((_, i) => i !== idx);
        }
        if (!multi && next.length > 1) next = next.filter(s => s.key === key);
      }
      // Fire server-side callback
      if (onSort && next.length) onSort(next[next.length - 1]);
      return next;
    });
    setPage(1);
  }

  // ─────────────────────────────────────────────────────────────
  // SELECTION LOGIC
  // ─────────────────────────────────────────────────────────────

  function fireSelection(set) {
    if (!onSelectionChange) return;
    const data = getPageData();
    onSelectionChange(data.filter((r, i) => set.has(rowKey(r, i))));
  }

  function toggleSelect(row, idx, shiftKey) {
    if (selection === 'none') return;
    const key = rowKey(row, idx);

    if (selection === 'single') {
      setSelected(prev => {
        const next = new Set();
        if (!prev.has(key)) next.add(key);
        fireSelection(next);
        return next;
      });
    } else {
      // multi
      if (shiftKey && lastClickIdx >= 0) {
        // Range select
        const rows = getPageData();
        const lo = Math.min(lastClickIdx, idx);
        const hi = Math.max(lastClickIdx, idx);
        setSelected(prev => {
          const next = new Set(prev);
          for (let i = lo; i <= hi; i++) next.add(rowKey(rows[i], i));
          fireSelection(next);
          return next;
        });
      } else {
        setSelected(prev => {
          const next = new Set(prev);
          next.has(key) ? next.delete(key) : next.add(key);
          fireSelection(next);
          return next;
        });
      }
      lastClickIdx = idx;
    }
  }

  function toggleSelectAll() {
    const rows = getPageData();
    const sel = selected();
    const allKeys = rows.map((r, i) => rowKey(r, i));
    const allSelected = allKeys.length > 0 && allKeys.every(k => sel.has(k));
    const next = new Set(sel);
    if (allSelected) {
      allKeys.forEach(k => next.delete(k));
    } else {
      allKeys.forEach(k => next.add(k));
    }
    setSelected(next);
    fireSelection(next);
  }

  // ─────────────────────────────────────────────────────────────
  // EXPAND LOGIC
  // ─────────────────────────────────────────────────────────────

  function toggleExpand(row, idx) {
    const key = rowKey(row, idx);
    setExpanded(prev => {
      const next = new Set(prev);
      next.has(key) ? next.delete(key) : next.add(key);
      return next;
    });
  }

  // ─────────────────────────────────────────────────────────────
  // FILTER LOGIC
  // ─────────────────────────────────────────────────────────────

  function setFilter(key, value) {
    setFilters(prev => ({ ...prev, [key]: value }));
    setPage(1);
  }

  // ─────────────────────────────────────────────────────────────
  // EXPORT
  // ─────────────────────────────────────────────────────────────

  function exportCSV() {
    const rows = getSorted();
    const header = rawCols.map(c => csvCell(c.label)).join(',');
    const body = rows.map(r => rawCols.map(c => csvCell(r[c.key])).join(',')).join('\n');
    const csv = header + '\n' + body;
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'data.csv';
    a.click();
    URL.revokeObjectURL(url);
  }

  // ─────────────────────────────────────────────────────────────
  // CELL EDITING
  // ─────────────────────────────────────────────────────────────

  function startEdit(td, row, col) {
    if (td.querySelector('input')) return;
    const oldValue = row[col.key];
    td.classList.add('d-datatable-td-editing');
    const input = h('input', {
      type: 'text',
      value: oldValue != null ? String(oldValue) : '',
      class: 'd-datatable-edit-input',
      onKeydown(e) {
        if (e.key === 'Enter') commitEdit();
        if (e.key === 'Escape') cancelEdit();
      },
      onBlur() { commitEdit(); }
    });

    td.textContent = '';
    td.appendChild(input);
    input.focus();
    input.select();

    function commitEdit() {
      const newValue = input.value;
      td.classList.remove('d-datatable-td-editing');
      td.textContent = newValue;
      if (newValue !== String(oldValue ?? '') && onCellEdit) {
        onCellEdit({ row, column: col, value: newValue, oldValue });
      }
    }

    function cancelEdit() {
      td.classList.remove('d-datatable-td-editing');
      td.textContent = oldValue != null ? String(oldValue) : '';
    }
  }

  // ─────────────────────────────────────────────────────────────
  // COLUMN RESIZE
  // ─────────────────────────────────────────────────────────────

  function initResize(e, col, thEl) {
    e.preventDefault();
    const startX = e.clientX;
    const startW = thEl.offsetWidth;

    function onMove(ev) {
      const diff = ev.clientX - startX;
      const newW = Math.max(MIN_COL_W, startW + diff);
      setColWidths(prev => ({ ...prev, [col.key]: newW }));
      thEl.style.width = newW + 'px';
    }

    function onUp() {
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    }

    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  }

  // ─────────────────────────────────────────────────────────────
  // PIN OFFSET CALCULATION
  // ─────────────────────────────────────────────────────────────

  /** Compute left/right sticky offsets for pinned columns */
  function getPinOffsets() {
    const widths = colWidths();
    const leftPins = [];
    const rightPins = [];
    const allCols = getEffectiveCols();

    // Gather pinned indices
    allCols.forEach((c, i) => {
      if (c.pinned === 'left') leftPins.push(i);
      if (c.pinned === 'right') rightPins.push(i);
    });

    const offsets = {};
    let leftAcc = 0;
    for (const i of leftPins) {
      offsets[i] = { left: leftAcc };
      const w = widths[allCols[i].key] || parseInt(allCols[i].width) || 150;
      leftAcc += w;
    }

    let rightAcc = 0;
    for (let j = rightPins.length - 1; j >= 0; j--) {
      const i = rightPins[j];
      offsets[i] = { right: rightAcc };
      const w = widths[allCols[i].key] || parseInt(allCols[i].width) || 150;
      rightAcc += w;
    }

    return offsets;
  }

  // ─────────────────────────────────────────────────────────────
  // EFFECTIVE COLUMNS (with selection/expand cols prepended)
  // ─────────────────────────────────────────────────────────────

  function getEffectiveCols() { return rawCols; }

  // ─────────────────────────────────────────────────────────────
  // BUILD DOM
  // ─────────────────────────────────────────────────────────────

  // Root wrapper
  const root = h('div', {
    class: cx('d-datatable', cls),
    role: 'region',
    'aria-label': 'Data table'
  });

  // ── Toolbar ──────────────────────────────────────────────────

  if (exportable) {
    const toolbar = h('div', { class: 'd-datatable-header' },
      h('button', {
        class: 'd-datatable-export-btn',
        type: 'button',
        onclick: exportCSV,
        'aria-label': 'Export as CSV'
      }, 'Export CSV')
    );
    root.appendChild(toolbar);
  }

  // ── Scroll container ────────────────────────────────────────

  const scrollWrap = h('div', {
    class: 'd-datatable-scroll',
    style: { overflow: 'auto', position: 'relative' }
  });

  // ── Table element ───────────────────────────────────────────

  const table = h('table', {
    class: cx(
      'd-datatable-table',
      striped && 'd-datatable-striped',
      hoverable && 'd-datatable-hoverable'
    ),
    role: 'grid'
  });

  // ── Build thead ─────────────────────────────────────────────

  const thead = h('thead', { class: stickyHeader ? 'd-datatable-sticky' : null });
  const headerRow = h('tr', null);

  // Expand spacer column
  if (expandable) {
    headerRow.appendChild(h('th', {
      class: 'd-datatable-th',
      style: { width: '40px' },
      'aria-label': 'Expand'
    }));
  }

  // Selection column
  if (selection === 'multi') {
    const selAllTh = h('th', { class: 'd-datatable-th', style: { width: '40px' } });
    const cb = h('input', {
      type: 'checkbox',
      class: 'd-datatable-checkbox',
      'aria-label': 'Select all rows',
      onchange: toggleSelectAll
    });
    selAllTh.appendChild(cb);
    headerRow.appendChild(selAllTh);

    // Sync select-all state
    createEffect(() => {
      const sel = selected();
      const rows = getPageData();
      const allKeys = rows.map((r, i) => rowKey(r, i));
      const allSel = allKeys.length > 0 && allKeys.every(k => sel.has(k));
      const someSel = !allSel && allKeys.some(k => sel.has(k));
      cb.checked = allSel;
      cb.indeterminate = someSel;
    });
  }

  // Data columns
  rawCols.forEach((col, ci) => {
    const th = h('th', {
      class: cx(
        'd-datatable-th',
        col.sortable && 'd-datatable-th-sortable',
        col.pinned === 'left' && 'd-datatable-pinned-left',
        col.pinned === 'right' && 'd-datatable-pinned-right'
      ),
      style: {
        width: col.width || 'auto',
        textAlign: col.align || 'left',
        ...(col.pinned ? { position: 'sticky', zIndex: 3 } : {})
      },
      'aria-sort': 'none'
    });

    // Label
    const labelSpan = h('span', null, col.label);
    th.appendChild(labelSpan);

    // Sort indicator
    if (col.sortable) {
      const sortIndicator = h('span', {
        class: 'd-datatable-sort-icon',
        'aria-hidden': 'true'
      });
      th.appendChild(sortIndicator);

      // Sort effect
      createEffect(() => {
        const sc = sortCols();
        const entry = sc.find(s => s.key === col.key);
        sortIndicator.replaceChildren(entry ? (entry.direction === 'asc' ? caret('up') : caret('down')) : caret('down'));
        th.setAttribute('aria-sort', entry ? (entry.direction === 'asc' ? 'ascending' : 'descending') : 'none');
        th.classList.toggle('d-datatable-th-sorted-asc', !!(entry && entry.direction === 'asc'));
        th.classList.toggle('d-datatable-th-sorted-desc', !!(entry && entry.direction === 'desc'));
      });

      th.addEventListener('click', (e) => {
        handleSort(col.key, e.shiftKey);
      });
      th.style.cursor = 'pointer';
      th.style.userSelect = 'none';
    }

    // Filter icon + popup
    if (col.filterable) {
      const filterWrap = h('span', { style: { position: 'relative', display: 'inline-block', marginLeft: '4px' } });
      const filterBtn = h('button', {
        class: 'd-datatable-filter-icon',
        type: 'button',
        'aria-label': `Filter ${col.label}`,
        onclick(e) {
          e.stopPropagation();
          const popup = filterWrap.querySelector('.d-datatable-filter-popup');
          if (popup) {
            popup.style.display = popup.style.display === 'none' ? 'block' : 'none';
            if (popup.style.display === 'block') popup.querySelector('input').focus();
          }
        }
      }, '\u25BD');

      const filterPopup = h('div', {
        class: 'd-datatable-filter-popup',
        style: { display: 'none' },
        onclick(e) { e.stopPropagation(); }
      });
      const filterInput = h('input', {
        type: 'text',
        placeholder: `Filter ${col.label}...`,
        'aria-label': `Filter by ${col.label}`,
        oninput(e) { setFilter(col.key, e.target.value); }
      });
      filterPopup.appendChild(filterInput);
      filterWrap.appendChild(filterBtn);
      filterWrap.appendChild(filterPopup);
      th.appendChild(filterWrap);

      // Update filter icon active state
      createEffect(() => {
        const f = filters();
        filterBtn.classList.toggle('d-datatable-filter-active', !!f[col.key]);
      });
    }

    // Resize handle
    const handle = h('span', {
      class: 'd-datatable-resize-handle',
      onmousedown(e) { initResize(e, col, th); },
      'aria-hidden': 'true'
    });
    th.appendChild(handle);

    headerRow.appendChild(th);
  });

  thead.appendChild(headerRow);
  table.appendChild(thead);

  // ── Build tbody (reactive) ──────────────────────────────────

  const tbody = h('tbody', null);
  table.appendChild(tbody);

  // Virtual scroll state
  let useVirtual = false;
  let visibleStart = 0;
  let visibleEnd = 0;
  const spacerTop = h('tr', { style: { height: '0px' }, 'aria-hidden': 'true' },
    h('td', { style: { padding: 0, border: 'none' } })
  );
  const spacerBottom = h('tr', { style: { height: '0px' }, 'aria-hidden': 'true' },
    h('td', { style: { padding: 0, border: 'none' } })
  );

  /** Build a single row (tr + optional expand tr) */
  function buildRow(row, idx) {
    const key = rowKey(row, idx);
    const sel = selected();
    const exp = expanded();
    const isSelected = sel.has(key);
    const isExpanded = exp.has(key);

    const tr = h('tr', {
      class: cx(
        'd-datatable-row',
        isSelected && 'd-datatable-row-selected',
        isExpanded && 'd-datatable-row-expanded'
      ),
      onclick(e) { toggleSelect(row, idx, e.shiftKey); },
      'data-row-key': key
    });

    // Expand toggle cell
    if (expandable) {
      const expandTd = h('td', { class: 'd-datatable-td', style: { width: '40px', textAlign: 'center' } });
      const expandBtn = h('button', {
        type: 'button',
        class: 'd-datatable-expand-btn',
        'aria-label': isExpanded ? 'Collapse row' : 'Expand row',
        'aria-expanded': isExpanded ? 'true' : 'false',
        onclick(e) {
          e.stopPropagation();
          toggleExpand(row, idx);
        }
      }, isExpanded ? caret('down') : caret('right'));
      expandTd.appendChild(expandBtn);
      tr.appendChild(expandTd);
    }

    // Selection checkbox cell
    if (selection === 'multi') {
      const cbTd = h('td', { class: 'd-datatable-td', style: { width: '40px', textAlign: 'center' } });
      const cb = h('input', {
        type: 'checkbox',
        class: 'd-datatable-checkbox',
        checked: isSelected ? '' : undefined,
        'aria-label': `Select row ${idx + 1}`,
        onclick(e) { e.stopPropagation(); },
        onchange() { toggleSelect(row, idx, false); }
      });
      if (isSelected) cb.checked = true;
      cbTd.appendChild(cb);
      tr.appendChild(cbTd);
    }

    // Data cells
    rawCols.forEach(col => {
      const val = row[col.key];
      const content = col.render ? col.render(val, row) : (val != null ? String(val) : '');

      const td = h('td', {
        class: cx(
          'd-datatable-td',
          col.pinned === 'left' && 'd-datatable-pinned-left',
          col.pinned === 'right' && 'd-datatable-pinned-right'
        ),
        style: {
          textAlign: col.align || 'left',
          ...(col.pinned ? { position: 'sticky', zIndex: 1 } : {})
        }
      });

      if (typeof content === 'object' && content instanceof Node) {
        td.appendChild(content);
      } else {
        td.textContent = content;
      }

      // Editable: double-click to edit
      if (col.editable) {
        td.addEventListener('dblclick', (e) => {
          e.stopPropagation();
          startEdit(td, row, col);
        });
        td.style.cursor = 'text';
      }

      tr.appendChild(td);
    });

    const frag = [tr];

    // Expansion row
    if (expandable && isExpanded && expandRender) {
      const totalCols = rawCols.length + (selection === 'multi' ? 1 : 0) + 1;
      const expandTr = h('tr', { class: 'd-datatable-expand-row' });
      const expandTd = h('td', { colspan: totalCols, class: 'd-datatable-td' });
      const content = expandRender(row);
      if (content instanceof Node) expandTd.appendChild(content);
      else expandTd.textContent = content;
      expandTr.appendChild(expandTd);
      frag.push(expandTr);
    }

    return frag;
  }

  /** Full tbody rebuild (reactive) */
  createEffect(() => {
    const rows = getPageData();
    const _sel = selected(); // track
    const _exp = expanded(); // track
    const _filters = filters(); // track
    const _sort = sortCols(); // track
    const _pg = page(); // track
    const _ps = pageSize(); // track

    // Clear tbody
    while (tbody.firstChild) tbody.removeChild(tbody.firstChild);

    if (rows.length === 0) {
      const totalCols = rawCols.length
        + (selection === 'multi' ? 1 : 0)
        + (expandable ? 1 : 0);
      tbody.appendChild(
        h('tr', { class: 'd-datatable-empty' },
          h('td', { colspan: totalCols, class: 'd-datatable-td' }, emptyText)
        )
      );
      return;
    }

    // Virtual scrolling
    useVirtual = rows.length > VIRT_THRESHOLD;

    if (useVirtual) {
      const containerH = scrollWrap.clientHeight || 400;
      const st = scrollTop();
      visibleStart = Math.max(0, Math.floor(st / ROW_H) - 5);
      visibleEnd = Math.min(rows.length, Math.ceil((st + containerH) / ROW_H) + 5);

      spacerTop.style.height = (visibleStart * ROW_H) + 'px';
      spacerBottom.style.height = ((rows.length - visibleEnd) * ROW_H) + 'px';

      tbody.appendChild(spacerTop);
      for (let i = visibleStart; i < visibleEnd; i++) {
        const trs = buildRow(rows[i], i);
        trs.forEach(tr => tbody.appendChild(tr));
      }
      tbody.appendChild(spacerBottom);
    } else {
      const frag = document.createDocumentFragment();
      for (let i = 0; i < rows.length; i++) {
        const trs = buildRow(rows[i], i);
        trs.forEach(tr => frag.appendChild(tr));
      }
      tbody.appendChild(frag);
    }
  });

  // Virtual scroll listener
  scrollWrap.addEventListener('scroll', () => {
    if (useVirtual) setScrollTop(scrollWrap.scrollTop);
  });

  scrollWrap.appendChild(table);
  root.appendChild(scrollWrap);

  // ── Pagination ──────────────────────────────────────────────

  if (pgCfg) {
    const pgBar = h('div', { class: 'd-datatable-pagination', role: 'navigation', 'aria-label': 'Table pagination' });

    // Page size selector
    const sizeLabel = h('label', { class: 'd-datatable-page-size' },
      'Rows: '
    );
    const sizeSelect = h('select', {
      'aria-label': 'Rows per page',
      onchange(e) {
        batch(() => {
          setPageSize(Number(e.target.value));
          setPage(1);
        });
        if (pgCfg.onPageChange) pgCfg.onPageChange({ page: 1, pageSize: Number(e.target.value) });
      }
    });
    [10, 20, 50, 100].forEach(n => {
      const opt = h('option', { value: n }, String(n));
      if (n === (pgCfg.pageSize || 10)) opt.selected = true;
      sizeSelect.appendChild(opt);
    });
    sizeLabel.appendChild(sizeSelect);
    pgBar.appendChild(sizeLabel);

    // Info text
    const pgInfo = h('span', { class: 'd-datatable-page-info' });
    pgBar.appendChild(pgInfo);

    // Nav buttons
    const prevBtn = h('button', {
      type: 'button',
      class: 'd-datatable-page-btn',
      'aria-label': 'Previous page',
      onclick() {
        const p = page();
        if (p > 1) {
          setPage(p - 1);
          if (pgCfg.onPageChange) pgCfg.onPageChange({ page: p - 1, pageSize: pageSize() });
        }
      }
    }, '\u2039 Prev');

    const nextBtn = h('button', {
      type: 'button',
      class: 'd-datatable-page-btn',
      'aria-label': 'Next page',
      onclick() {
        const p = page();
        if (p < getPageCount()) {
          setPage(p + 1);
          if (pgCfg.onPageChange) pgCfg.onPageChange({ page: p + 1, pageSize: pageSize() });
        }
      }
    }, 'Next \u203A');

    pgBar.appendChild(prevBtn);
    pgBar.appendChild(nextBtn);

    // Update pagination state reactively
    createEffect(() => {
      const p = page();
      const pc = getPageCount();
      const total = getTotal();
      const ps = pageSize();
      const start = (p - 1) * ps + 1;
      const end = Math.min(p * ps, total);
      pgInfo.textContent = total > 0 ? `${start}\u2013${end} of ${total}` : '0 results';
      prevBtn.disabled = p <= 1;
      nextBtn.disabled = p >= pc;
    });

    root.appendChild(pgBar);
  }

  // ── Pin offsets (applied after mount via effect) ────────────

  createEffect(() => {
    const _cw = colWidths(); // track
    const offsets = getPinOffsets();
    // Apply to TH and TD elements
    const allCols = getEffectiveCols();
    const ths = headerRow.querySelectorAll('.d-datatable-th');

    // Calculate actual offsets from rendered widths
    let leftAcc = 0;
    const extraCols = (expandable ? 1 : 0) + (selection === 'multi' ? 1 : 0);

    allCols.forEach((col, ci) => {
      if (!col.pinned) return;
      const thIdx = ci + extraCols;
      const th = ths[thIdx];
      if (!th) return;

      if (col.pinned === 'left') {
        th.style.left = leftAcc + 'px';
        // Apply to all body cells in this column
        const tds = tbody.querySelectorAll(`tr > .d-datatable-td:nth-child(${thIdx + 1})`);
        tds.forEach(td => { td.style.left = leftAcc + 'px'; });
        leftAcc += th.offsetWidth;
      }
    });

    // Right pins (reverse)
    let rightAcc = 0;
    for (let ci = allCols.length - 1; ci >= 0; ci--) {
      const col = allCols[ci];
      if (col.pinned !== 'right') continue;
      const thIdx = ci + extraCols;
      const th = ths[thIdx];
      if (!th) continue;
      th.style.right = rightAcc + 'px';
      const tds = tbody.querySelectorAll(`tr > .d-datatable-td:nth-child(${thIdx + 1})`);
      tds.forEach(td => { td.style.right = rightAcc + 'px'; });
      rightAcc += th.offsetWidth;
    }
  });

  return root;
}
